## 任务一：改写 AI 调用模块

**改 `/Users/admin/tianzi-rike/lib/claude.ts`**：

当前代码用 `@anthropic-ai/sdk`，需要改为用 fetch 直接调用 DeepSeek API：
- Endpoint: `https://api.deepseek.com/chat/completions`
- API Key: 从环境变量 `CLAUDE_API_KEY` 读取（已配在 `.env.local`）
- 模型: `deepseek-chat`
- Headers: `Authorization: Bearer ${apiKey}`, `Content-Type: application/json`
- Body: `{ model, messages: [{ role: "system", content: systemPrompt }, { role: "user", content: prompt }], max_tokens, temperature: 0.7 }`
- 保留原有 `getAIRecommendation(prompt: string)` 的函数签名不变，调用方不需要改

```typescript
const DEEPSEEK_BASE = "https://api.deepseek.com/chat/completions";
const API_KEY = process.env.CLAUDE_API_KEY || "";

export async function getAIRecommendation(prompt: string): Promise<string> {
  if (!API_KEY) throw new Error("API key not configured");

  const res = await fetch(DEEPSEEK_BASE, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "Authorization": `Bearer ${API_KEY}`,
    },
    body: JSON.stringify({
      model: "deepseek-chat",
      messages: [
        { role: "system", content: "你是一位专业的个人成长教练。回复简洁有力，风格如帝王侍读。每段不超过3句话。" },
        { role: "user", content: prompt },
      ],
      max_tokens: 1024,
      temperature: 0.7,
    }),
  });

  if (!res.ok) {
    const errText = await res.text().catch(() => "");
    throw new Error(`DeepSeek API error ${res.status}: ${errText}`);
  }

  const data = await res.json();
  return data.choices?.[0]?.message?.content || "";
}
```

## 任务二：新增 AI 每日小结（daily-summary）

**改 `/Users/admin/tianzi-rike/app/api/insights/route.ts`**：

在现有的 `type === "generate-habits"` 之后，`return NextResponse.json({ error: "Unknown type" })` 之前，新增 `daily-summary` 处理：

```typescript
if (type === "daily-summary") {
  const habits = store.habits.filter((h: any) => h.isActive);
  const todayStr = new Date().toISOString().split("T")[0];
  const todayLogs = store.habitLogs.filter((l: any) => l.date === todayStr);
  const completedCount = todayLogs.filter((l: any) => l.completed).length;
  const totalCount = habits.length;
  const completionRate = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;

  // 连续天数
  let streak = 0;
  const now = new Date();
  for (let i = 0; i < 365; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const ds = d.toISOString().split("T")[0];
    const dayCompleted = store.habitLogs.filter((l: any) => l.date === ds && l.completed).length;
    if (dayCompleted > 0) streak++;
    else break;
  }

  // 昨日复盘
  const yesterday = new Date(now);
  yesterday.setDate(yesterday.getDate() - 1);
  const yesterdayStr = yesterday.toISOString().split("T")[0];
  const yesterdayReview = store.reviews.find((r: any) => r.date === yesterdayStr);

  const message = `用户今日打卡情况：完成 ${completedCount}/${totalCount} 项习惯，完成率 ${completionRate}%，连续 ${streak} 天。${yesterdayReview ? `昨日复盘："${yesterdayReview.summary}"` : ""}请用帝王侍读的口吻，给一段温暖、简洁的今日小结（80-120字），既肯定成就又温和提醒不足。`;

  const text = await getAIRecommendation(message);
  return NextResponse.json({ text });
}
```

## 任务三：新增 AI 明日目标推荐（daily-goals）

同样在 insights/route.ts 中新增：

```typescript
if (type === "daily-goals") {
  const habits = store.habits.filter((h: any) => h.isActive);
  const now = new Date();

  // 近14天各习惯完成率
  const habitStats = habits.map((h: any) => {
    let completed = 0;
    let total = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = store.habitLogs.find((l: any) => l.habitId === h.id && l.date === ds);
      total++;
      if (log?.completed) completed++;
    }
    return { title: h.title, completionRate: Math.round((completed / total) * 100), streak: 0 };
  });

  // 查断档
  habitStats.forEach((hs: any) => {
    let s = 0;
    for (let i = 1; i <= 14; i++) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const ds = d.toISOString().split("T")[0];
      const log = store.habitLogs.find((l: any) => l.habitId === habits.find((h: any) => h.title === hs.title)?.id && l.date === ds);
      if (!log?.completed) break;
      s++;
    }
    hs.streak = s;
  });

  const message = `用户近14天各习惯完成率：${habitStats.map((hs: any) => `${hs.title}(${hs.completionRate}%)`).join("，")}。连续未做的习惯：${habitStats.filter((hs: any) => hs.streak === 0).map((hs: any) => hs.title).join("、") || "无"}。请基于以上数据，推荐2-3条明日具体可执行的行动建议。返回 JSON 数组格式：[{"title":"...","detail":"...","reason":"..."}]，不要 markdown 包裹，只返回纯 JSON。`;

  const text = await getAIRecommendation(message);
  try {
    const goals = JSON.parse(text);
    return NextResponse.json({ goals: Array.isArray(goals) ? goals : [] });
  } catch {
    return NextResponse.json({ goals: [] });
  }
}
```

